module top_module(
    input [15:0] num,
    output reg [3:0] ones_count // Change output to reg type
);integer i;
reg [15:0] obf_temp;

always @(*) begin
    ones_count = 0;
    obf_temp = num;
    for (i = 0; i < 16; i = i + 1) begin
        ones_count = ones_count + obf_temp[0];
        obf_temp = obf_temp >> 1;
    end
end

endmodule
